// Decide which agent handles this message and which hermes gateway to call.
// Routing is config-driven: set the n8n environment variable GHIATH_ROUTES to a
// JSON object to match your agents.conf. Falls back to the neutral defaults
// (assistant / engineer / researcher) so it works out of the box.
// Example GHIATH_ROUTES value:
//   {"assistant":{"port":8642,"model":"deepseek/deepseek-v2-flash","folder":"scratchpads","default":true},
//    "engineer":{"port":8643,"model":"anthropic/claude-opus-4-8","folder":"projects","match":"build|code|implement|refactor|debug|bug|deploy"},
//    "researcher":{"port":8644,"model":"z-ai/glm-4.6","folder":"memory","match":"research|investigate|find out|literature"}}
const DEFAULT_ROUTES = {
  assistant:  { port: 8642, model: 'deepseek/deepseek-v2-flash', folder: 'scratchpads', default: true },
  engineer:   { port: 8643, model: 'anthropic/claude-opus-4-8', folder: 'projects', match: 'build|code|ngoding|implement|refactor|debug|bug|deploy' },
  researcher: { port: 8644, model: 'z-ai/glm-4.6', folder: 'memory', match: 'research|cari|riset|investigate|find out|literature' },
};

let routes = DEFAULT_ROUTES;
try { if ($env.GHIATH_ROUTES) routes = JSON.parse($env.GHIATH_ROUTES); } catch (e) {}

const body = $input.first().json.body || $input.first().json;
const text = (body.message || body.text || '').toString();
const lower = text.toLowerCase();

// Pick the first agent whose "match" regex hits; otherwise the "default" agent.
let agent = Object.keys(routes).find(a => routes[a].default) || Object.keys(routes)[0];
for (const [name, cfg] of Object.entries(routes)) {
  if (cfg.match && new RegExp(cfg.match).test(lower)) { agent = name; break; }
}
const r = routes[agent];
const url = `http://host.docker.internal:${r.port}/v1/chat/completions`;
const folder = r.folder;

// Instruct the agent to persist its output as a schema-compliant "result" note
// (status "done" so the vault-watch workflow does not re-trigger it).
const prompt = `${text}\n\nWhen you are done, save a concise note of your result into ${folder}/ with a descriptive filename. Begin the file with YAML front-matter: type: result, status: done, owner: ${agent}, from: ${agent}, created (today's date), tags: [].`;

return [{ json: { agent, folder, url, model: r.model, prompt } }];
